+namespace Microsoft.SubscriptionBilling;
+
+using Microsoft.Inventory.Item;
+using Microsoft.Sales.Document;
+
+codeunit 139875 "Contract Invoice DocTotal Test"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+    Access = Internal;
+
+    var
+        ContractTestLibrary: Codeunit "Contract Test Library";
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+        LibraryRandom: Codeunit "Library - Random";
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryVariableStorage: Codeunit "Library - Variable Storage";
+        IsInitialized: Boolean;
+
+    [Test]
+    procedure SalesInvoiceShowsSubtotalForServCommItem()
+    var
+        Item: Record Item;
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+    begin
+        // [SCENARIO] When a Service Commitment Item is added to a Sales Invoice,
+        // the line should NOT be excluded from document totals.
+        // Contract Invoices are Sales Invoices and their totals must be visible.
+        Initialize();
+
+        // [GIVEN] An Item with "Subscription Option" = "Service Commitment Item" and a unit price
+        ContractTestLibrary.CreateItemWithServiceCommitmentOption(Item, Enum::"Item Service Commitment Type"::"Service Commitment Item");
+        ContractTestLibrary.UpdateItemUnitCostAndPrice(Item, LibraryRandom.RandDec(1000, 2), LibraryRandom.RandDec(1000, 2), true);
+
+        // [GIVEN] A Sales Invoice header
+        LibrarySales.CreateSalesHeader(SalesHeader, Enum::"Sales Document Type"::Invoice, '');
+
+        // [WHEN] A Sales Line is created with the Service Commitment Item on the Invoice
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, Item."No.", LibraryRandom.RandDec(10, 2));
+
+        // [THEN] The Sales Line should have a Line Amount
+        SalesLine.TestField("Line Amount");
+
+        // [THEN] "Exclude from Doc. Total" must be FALSE so the Invoice header shows correct totals
+        SalesLine.TestField("Exclude from Doc. Total", false);
+    end;
+
+    local procedure Initialize()
+    begin
+        LibraryVariableStorage.AssertEmpty();
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"Contract Invoice DocTotal Test");
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"Contract Invoice DocTotal Test");
+
+        ContractTestLibrary.DeleteAllContractRecords();
+
+        if IsInitialized then
+            exit;
+
+        ContractTestLibrary.InitContractsApp();
+        LibraryERMCountryData.UpdateSalesReceivablesSetup();
+        LibraryERMCountryData.UpdateGeneralLedgerSetup();
+        ContractTestLibrary.InitSourceCodeSetup();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"Contract Invoice DocTotal Test");
+
+        IsInitialized := true;
+    end;
+}

