+codeunit 134200 "ERM VAT Settl JnlTemplMandatory"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [VAT Settlement] [Journal Template Name Mandatory]
+        isInitialized := false;
+    end;
+
+    var
+        LibraryERM: Codeunit "Library - ERM";
+        LibraryRandom: Codeunit "Library - Random";
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryUtility: Codeunit "Library - Utility";
+        LibrarySetupStorage: Codeunit "Library - Setup Storage";
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        isInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure CalcPostVATSettlWithJnlTemplNameMandatory()
+    var
+        VATPostingSetup: Record "VAT Posting Setup";
+        GeneralLedgerSetup: Record "General Ledger Setup";
+        VATEntry: Record "VAT Entry";
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        CalcandPostVATSettlement: Report "Calc. and Post VAT Settlement";
+        CustomerNo: Code[20];
+        ItemNo: Code[20];
+        PostedDocNo: Code[20];
+        SettlementDocNo: Code[20];
+    begin
+        // [SCENARIO] Run Calc. and Post VAT Settlement report with Post option when
+        // "Journal Templ. Name Mandatory" is enabled in G/L Setup should not error.
+        Initialize();
+
+        // [GIVEN] "Journal Templ. Name Mandatory" is enabled in General Ledger Setup.
+        GeneralLedgerSetup.Get();
+        GeneralLedgerSetup.Validate("Journal Templ. Name Mandatory", true);
+        GeneralLedgerSetup.Modify(true);
+
+        // [GIVEN] A VAT Posting Setup with Normal VAT calculation type.
+        LibraryERM.CreateVATPostingSetupWithAccounts(
+            VATPostingSetup, VATPostingSetup."VAT Calculation Type"::"Normal VAT",
+            LibraryRandom.RandDecInRange(10, 20, 2));
+
+        // [GIVEN] A posted Sales Invoice creating VAT entries.
+        CustomerNo := LibrarySales.CreateCustomerWithVATBusPostingGroup(VATPostingSetup."VAT Bus. Posting Group");
+        ItemNo := LibraryInventory.CreateItemNoWithVATProdPostingGroup(VATPostingSetup."VAT Prod. Posting Group");
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Invoice, CustomerNo);
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, ItemNo, LibraryRandom.RandDecInRange(10, 20, 2));
+        SalesLine.Validate("Unit Price", LibraryRandom.RandDecInRange(100, 200, 2));
+        SalesLine.Modify(true);
+        PostedDocNo := LibrarySales.PostSalesDocument(SalesHeader, false, true);
+
+        // [WHEN] Run Calc. and Post VAT Settlement with Post = true.
+        SettlementDocNo := LibraryUtility.GenerateGUID();
+        CalcandPostVATSettlement.InitializeRequest(
+            WorkDate(), WorkDate(), WorkDate(), SettlementDocNo,
+            LibraryERM.CreateGLAccountNo(), false, true);
+        VATPostingSetup.SetRange("VAT Bus. Posting Group", VATPostingSetup."VAT Bus. Posting Group");
+        VATPostingSetup.SetRange("VAT Prod. Posting Group", VATPostingSetup."VAT Prod. Posting Group");
+        CalcandPostVATSettlement.SetTableView(VATPostingSetup);
+        CalcandPostVATSettlement.UseRequestPage(false);
+        Commit();
+        CalcandPostVATSettlement.Run();
+
+        // [THEN] No error occurs. Settlement VAT Entry is created and original entry is closed.
+        VATEntry.SetRange("Document No.", PostedDocNo);
+        VATEntry.SetRange(Type, VATEntry.Type::Sale);
+        VATEntry.FindFirst();
+        VATEntry.TestField(Closed, true);
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"ERM VAT Settl JnlTemplMandatory");
+        LibrarySetupStorage.Restore();
+        if isInitialized then
+            exit;
+
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"ERM VAT Settl JnlTemplMandatory");
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        LibraryERMCountryData.UpdateVATPostingSetup();
+        LibraryERMCountryData.UpdatePurchasesPayablesSetup();
+        LibrarySetupStorage.Save(Database::"General Ledger Setup");
+
+        isInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"ERM VAT Settl JnlTemplMandatory");
+    end;
+}

