+    begin
+        // [FEATURE] [Manufacturing] [Production Order] [Replan]
+        // [SCENARIO] Input Quantity on Prod. Order Routing Line is recalculated to remaining
+        // quantity when Replan is run after partial output has been posted.
+        Initialize();
+
+        // [GIVEN] A child item for the production BOM.
+        LibraryInventory.CreateItem(ChildItem);
+
+        // [GIVEN] A work center with calendar.
+        LibraryManufacturing.CreateWorkCenterWithCalendar(WorkCenter);
+
+        // [GIVEN] A certified serial routing with Setup Time = 10 and Run Time = 10.
+        LibraryManufacturing.CreateRoutingHeader(RoutingHeader, RoutingHeader.Type::Serial);
