+        // [GIVEN] A certified production BOM with the child item.
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, ChildItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
