+codeunit 137085 "SCM Prod. Order Comp. Rounding"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Manufacturing] [Production Order] [SCM]
+        IsInitialized := false;
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryManufacturing: Codeunit "Library - Manufacturing";
+        IsInitialized: Boolean;
+
+    [Test]
+    procedure ProdOrderCompQtyPerPreservedWhenUoMQtyRoundPrecIsOne()
+    var
+        CompItem: Record Item;
+        FGItem: Record Item;
+        CompItemUnitOfMeasure: Record "Item Unit of Measure";
+        ProductionBOMHeader: Record "Production BOM Header";
+        ProductionBOMLine: Record "Production BOM Line";
+        ProductionOrder: Record "Production Order";
+        ProdOrderComponent: Record "Prod. Order Component";
+        QtyPer: Decimal;
+    begin
+        // [SCENARIO] When a component's Item UOM has 'Qty. Rounding Precision' = 1 and the
+        // Production BOM has a fractional 'Quantity Per' (e.g. 0.09), the Prod. Order Component
+        // created by refreshing a Production Order should have the correct 'Qty. Per' and
+        // 'Expected Quantity' instead of 0.
+        Initialize();
+        QtyPer := 0.09;
+
+        // [GIVEN] A component item with Replenishment System = Purchase and Rounding Precision = 0.01.
+        LibraryInventory.CreateItem(CompItem);
+        CompItem.Validate("Replenishment System", CompItem."Replenishment System"::Purchase);
+        CompItem.Validate("Rounding Precision", 0.01);
+        CompItem.Modify(true);
+
+        // [GIVEN] The component item's base UOM has Qty. Rounding Precision = 1.
+        CompItemUnitOfMeasure.Get(CompItem."No.", CompItem."Base Unit of Measure");
+        CompItemUnitOfMeasure.Validate("Qty. Rounding Precision", 1);
+        CompItemUnitOfMeasure.Modify(true);
+
+        // [GIVEN] A finished good item with Replenishment System = Prod. Order.
+        LibraryInventory.CreateItem(FGItem);
+        FGItem.Validate("Replenishment System", FGItem."Replenishment System"::"Prod. Order");
+        FGItem.Validate("Rounding Precision", 1);
+        FGItem.Modify(true);
+
+        // [GIVEN] A certified Production BOM with the component having Quantity Per = 0.09.
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, FGItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeader, ProductionBOMLine, '', ProductionBOMLine.Type::Item, CompItem."No.", QtyPer);
+        LibraryManufacturing.UpdateProductionBOMStatus(ProductionBOMHeader, ProductionBOMHeader.Status::Certified);
+
+        // [GIVEN] Assign Production BOM to the FG item.
+        FGItem.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        FGItem.Modify(true);
+
+        // [WHEN] Create and refresh a Released Production Order for the FG item with Qty = 1.
+        LibraryManufacturing.CreateProductionOrder(
+            ProductionOrder, ProductionOrder.Status::Released,
+            ProductionOrder."Source Type"::Item, FGItem."No.", 1);
+        LibraryManufacturing.RefreshProdOrder(ProductionOrder, false, true, true, true, false);
+
+        // [THEN] Prod. Order Component has Quantity per = 0.09 (not rounded to 0).
+        ProdOrderComponent.SetRange("Prod. Order No.", ProductionOrder."No.");
+        ProdOrderComponent.SetRange("Item No.", CompItem."No.");
+        ProdOrderComponent.FindFirst();
+        Assert.AreEqual(QtyPer, ProdOrderComponent."Quantity per",
+            'Quantity per should not be rounded to 0 when UOM Qty. Rounding Precision is 1.');
+
+        // [THEN] Expected Quantity = 0.09 (not rounded to 0).
+        Assert.AreEqual(QtyPer, ProdOrderComponent."Expected Quantity",
+            'Expected Quantity should not be rounded to 0 when UOM Qty. Rounding Precision is 1.');
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"SCM Prod. Order Comp. Rounding");
+
+        if IsInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"SCM Prod. Order Comp. Rounding");
+
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+
+        IsInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"SCM Prod. Order Comp. Rounding");
+    end;
+}

