+    [Scope('OnPrem')]
+    procedure TotalOverdueLCYUsesTodayNotWorkDate()
+    var
+        FinanceCue: Record "Finance Cue";
+        DetailedCustLedgEntry: Record "Detailed Cust. Ledg. Entry";
+        AccountReceivablesKPIs: TestPage "Account Receivables KPIs";
+        OverdueAmountWithToday: Decimal;
+        OldWorkDate: Date;
+        DueDateBetweenWorkDateAndToday: Date;
+        EntryAmount: Decimal;
+    begin
+        // [SCENARIO] The "Total Overdue (LCY)" cue on the Account Receivables KPIs page
+        // uses Today() as the overdue date filter, not WorkDate().
+        // When WorkDate differs from Today, the cue should still reflect entries overdue as of Today.
+
+        // [GIVEN] WorkDate is set to 10 days before Today
+        OldWorkDate := WorkDate();
+        WorkDate(CalcDate('<-10D>', Today()));
+
+        // [GIVEN] A Detailed Cust. Ledg. Entry with "Initial Entry Due Date" between WorkDate and Today
+        // This entry is overdue relative to Today but NOT relative to WorkDate
+        DueDateBetweenWorkDateAndToday := CalcDate('<-3D>', Today());
+        EntryAmount := LibraryRandom.RandDecInRange(100, 1000, 2);
+        InsertDetailedCustLedgEntry(DueDateBetweenWorkDateAndToday, EntryAmount);
+
+        // Calculate the expected overdue amount using Today as the filter (correct behavior)
+        if not FinanceCue.Get() then begin
+            FinanceCue.Init();
+            FinanceCue.Insert();
+        end;
+        FinanceCue.SetRange("Overdue Date Filter", 0D, Today());
+        FinanceCue.CalcFields("Total Overdue (LCY)");
+        OverdueAmountWithToday := FinanceCue."Total Overdue (LCY)";
+
+        // [WHEN] The Account Receivables KPIs page is opened
+        AccountReceivablesKPIs.OpenView();
+
+        // [THEN] The displayed "Total Overdue (LCY)" matches calculation using Today(), not WorkDate()
+        AccountReceivablesKPIs."Sales - Total Overdue (LCY)".AssertEquals(OverdueAmountWithToday);
+
+        AccountReceivablesKPIs.Close();
+
+        // Cleanup
+        WorkDate(OldWorkDate);
+    end;
+
+    local procedure InsertDetailedCustLedgEntry(DueDate: Date; AmountLCY: Decimal)
+    var
+        DetailedCustLedgEntry: Record "Detailed Cust. Ledg. Entry";
+    begin
+        DetailedCustLedgEntry.Init();
+        DetailedCustLedgEntry."Entry No." :=
+            LibraryUtility.GetNewRecNo(DetailedCustLedgEntry, DetailedCustLedgEntry.FieldNo("Entry No."));
+        DetailedCustLedgEntry."Initial Entry Due Date" := DueDate;
+        DetailedCustLedgEntry."Amount (LCY)" := AmountLCY;
+        DetailedCustLedgEntry."Posting Date" := DueDate;
+        DetailedCustLedgEntry.Insert();
+    end;
+}

