@@ -0,0 +1,67 @@
+namespace Microsoft.SubscriptionBilling;
+
+using Microsoft.Inventory.Item;
+using Microsoft.Sales.Customer;
+
+codeunit 148161 "Change Contract Line Test"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+    Access = Internal;
+
+    var
+        Assert: Codeunit Assert;
+        ContractTestLibrary: Codeunit "Contract Test Library";
+
+    [Test]
+    procedure ChangeItemNoDisconnectsOldSubscriptionLine()
+    var
+        Customer: Record Customer;
+        CustomerContract: Record "Customer Subscription Contract";
+        CustomerContractLine1: Record "Cust. Sub. Contract Line";
+        CustomerContractLine2: Record "Cust. Sub. Contract Line";
+        Item3: Record Item;
+        OldSubscriptionLine: Record "Subscription Line";
+        NewSubscriptionLine: Record "Subscription Line";
+        OldSubscriptionLineEntryNo: Integer;
+    begin
+        // [SCENARIO] When changing the item no. on a manually created contract line,
+        // the old subscription line must be disconnected from the contract.
+        // This prevents stale subscription lines from being invoiced.
+
+        // [GIVEN] A Customer Subscription Contract with two manually created item lines
+        ClearAll();
+        ContractTestLibrary.InitContractsApp();
+        ContractTestLibrary.CreateCustomer(Customer);
+        ContractTestLibrary.CreateCustomerContract(CustomerContract, Customer."No.");
+        ContractTestLibrary.InsertCustomerContractItemLine(CustomerContract, CustomerContractLine1);
+        ContractTestLibrary.InsertCustomerContractItemLine(CustomerContract, CustomerContractLine2);
+
+        // Remember the subscription line entry no. for the original item on line 2
+        OldSubscriptionLineEntryNo := CustomerContractLine2."Subscription Line Entry No.";
+        Assert.AreNotEqual(0, OldSubscriptionLineEntryNo, 'Subscription Line Entry No. should be set after inserting contract line.');
+        OldSubscriptionLine.Get(OldSubscriptionLineEntryNo);
+        OldSubscriptionLine.TestField("Subscription Contract No.", CustomerContract."No.");
+
+        // [WHEN] The item no. on the second contract line is changed to a different item
+        ContractTestLibrary.CreateItemWithServiceCommitmentOption(Item3, "Item Service Commitment Type"::"Service Commitment Item");
+        CustomerContractLine2.Validate("No.", Item3."No.");
+        CustomerContractLine2.Modify(false);
+
+        // [THEN] The old subscription line is disconnected from the contract
+        OldSubscriptionLine.Get(OldSubscriptionLineEntryNo);
+        Assert.AreEqual('', OldSubscriptionLine."Subscription Contract No.",
+            'Old subscription line should have been disconnected from the contract after item change.');
+        Assert.AreEqual(0, OldSubscriptionLine."Subscription Contract Line No.",
+            'Old subscription line contract line no. should be cleared after item change.');
+
+        // [THEN] The new subscription line is connected to the contract
+        Assert.AreNotEqual(0, CustomerContractLine2."Subscription Line Entry No.",
+            'New Subscription Line Entry No. should be set after item change.');
+        Assert.AreNotEqual(OldSubscriptionLineEntryNo, CustomerContractLine2."Subscription Line Entry No.",
+            'New subscription line should have a different Entry No. than the old one.');
+        NewSubscriptionLine.Get(CustomerContractLine2."Subscription Line Entry No.");
+        NewSubscriptionLine.TestField("Subscription Contract No.", CustomerContract."No.");
+        NewSubscriptionLine.TestField("Subscription Contract Line No.", CustomerContractLine2."Line No.");
+    end;
+}

