+        Quantity: Decimal;
+    begin
+        // [SCENARIO] Item Charge can be pulled into Sales Return Order via Get Posted Document Lines to Reverse
+        // when Default Qty. to Ship is set to Blank on Sales & Receivables Setup.
+        Initialize();
+
+        // [GIVEN] A Sales Order with an Item line and an Item Charge line assigned to the Item line
+        LibraryInventory.CreateItem(Item);
+        LibraryInventory.CreateItemCharge(ItemCharge);
+        Quantity := LibraryRandom.RandIntInRange(1, 25);
+
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Order, LibrarySales.CreateCustomerNo());
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, Item."No.", Quantity);
