+        // [GIVEN] Default Quantity to Ship is set to Blank in Sales & Receivables Setup
+        SalesReceivablesSetup.Get();
+        SalesReceivablesSetup.Validate(
+            "Default Quantity to Ship", SalesReceivablesSetup."Default Quantity to Ship"::Blank);
+        SalesReceivablesSetup.Modify(true);
+
+        // [WHEN] Creating a Sales Return Order and getting posted document lines to reverse
