+        JobPlanningLine: Record "Job Planning Line";
+        PurchaseHeader: Record "Purchase Header";
+        PurchaseLine: Record "Purchase Line";
+        Job: Record Job;
+        JobTask: Record "Job Task";
+        Vendor: Record Vendor;
+        Quantity: Decimal;
+    begin
+        // [SCENARIO] Non-inventory and service items should not allow reservation for job planning lines
+        // Per documentation: https://learn.microsoft.com/en-us/dynamics365/business-central/inventory-about-item-types
+        // Non-Inventory and Service items do not support the reservation functionality.
+
+        Initialize();
+
+        // [GIVEN] A non-inventory type item
+        LibraryInventory.CreateNonInventoryTypeItem(Item);
+        Quantity := LibraryRandom.RandDecInRange(5, 10, 2);
+
+        // [GIVEN] A purchase order with the non-inventory item
+        LibraryPurchase.CreateVendor(Vendor);
+        LibraryPurchase.CreatePurchHeader(PurchaseHeader, PurchaseHeader."Document Type"::Order, Vendor."No.");
+        LibraryPurchase.CreatePurchaseLine(PurchaseLine, PurchaseHeader, PurchaseLine.Type::Item, Item."No.", Quantity);
+
+        // [GIVEN] A job planning line with the same non-inventory item, Usage Link = true, Reserve = Optional
+        LibraryJob.CreateJob(Job);
