+codeunit 134980 "Issued Reminder Email Test"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+    EventSubscriberInstance = Manual;
+
+    var
+        LibraryVariableStorage: Codeunit "Library - Variable Storage";
+        Assert: Codeunit Assert;
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryUtility: Codeunit "Library - Utility";
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure IssuedReminderEmailIncludesCustomerAsRelatedSource()
+    var
+        Customer: Record Customer;
+        IssuedReminderHeader: Record "Issued Reminder Header";
+        ReportSelections: Record "Report Selections";
+        IssuedReminderEmailTest: Codeunit "Issued Reminder Email Test";
+    begin
+        // [FEATURE] [Issued Reminders] [Email]
+        // [SCENARIO] Sending email for an issued reminder should include the customer as a related entity
+        // in the email source records, so the email appears in the customer's sent email history.
+        LibraryVariableStorage.Clear();
+
+        // [GIVEN] A customer
+        LibrarySales.CreateCustomer(Customer);
+
+        // [GIVEN] An issued reminder for the customer
+        IssuedReminderHeader.Init();
+        IssuedReminderHeader."No." := LibraryUtility.GenerateGUID();
+        IssuedReminderHeader."Customer No." := Customer."No.";
+        IssuedReminderHeader.Insert(false);
+
+        // [WHEN] Email sending is triggered for the issued reminder
+        BindSubscription(IssuedReminderEmailTest);
+        IssuedReminderHeader.SetRecFilter();
+        ReportSelections.SendEmailToCust(
+            ReportSelections.Usage::Reminder.AsInteger(),
+            IssuedReminderHeader,
+            IssuedReminderHeader."No.",
+            'Issued Reminder',
+            true,
+            Customer."No.");
+        UnbindSubscription(IssuedReminderEmailTest);
+
+        // [THEN] The customer is included as a related entity in the email source records
+        Assert.IsTrue(
+            LibraryVariableStorage.DequeueBoolean(),
+            'Customer should be added as a related entity in email source records for issued reminders');
+    end;
+
+    [EventSubscriber(ObjectType::Table, Database::"Report Selections", 'OnSendEmailDirectlyOnBeforeSend', '', false, false)]
+    local procedure HandleOnSendEmailDirectlyOnBeforeSend(var ReportSelections: Record "Report Selections"; ReportUsage: Enum "Report Selection Usage"; RecordVariant: Variant; var DocNo: Code[20]; var DocName: Text[150]; FoundBody: Boolean; FoundAttachment: Boolean; var EmailBody: Codeunit "Temp Blob"; var DefaultEmailAddress: Text[250]; ShowDialog: Boolean; var TempAttachReportSelections: Record "Report Selections" temporary; var CustomReportSelection: Record "Custom Report Selection"; var AllEmailsWereSuccessful: Boolean; var IsHandled: Boolean; var SourceTableIDs: List of [Integer]; var SourceIDs: List of [Guid]; var SourceRelationTypes: List of [Integer])
+    begin
+        LibraryVariableStorage.Enqueue(SourceTableIDs.Contains(Database::Customer));
+        IsHandled := true;
+        AllEmailsWereSuccessful := true;
+    end;
+}

