+codeunit 134291 "Non-Ded. VAT Full VAT Journal"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Non Deductible VAT] [Full VAT]
+    end;
+
+    var
+        LibraryERM: Codeunit "Library - ERM";
+        LibraryJournals: Codeunit "Library - Journals";
+        LibraryNonDeductibleVAT: Codeunit "Library - NonDeductible VAT";
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibrarySetupStorage: Codeunit "Library - Setup Storage";
+        LibraryRandom: Codeunit "Library - Random";
+        IsInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure FullVATWithNonDeductiblePostsToNonDeductibleVATAmount()
+    var
+        VATPostingSetup: Record "VAT Posting Setup";
+        GenJournalLine: Record "Gen. Journal Line";
+        GLAccount: Record "G/L Account";
+        VATEntry: Record "VAT Entry";
+    begin
+        // [SCENARIO] When posting a journal line with Full VAT and 100% Non-Deductible VAT,
+        // the VAT amount should be posted as Non-Deductible VAT Amount, not as deductible Amount.
+        // Bug: Full VAT calculation type was excluded from non-deductible VAT processing,
+        // causing VAT to be treated as fully deductible.
+
+        Initialize();
+
+        // [GIVEN] VAT Posting Setup with "VAT Calculation Type" = "Full VAT" and "Non-Deductible VAT %" = 100
+        CreateNonDeductibleFullVATPostingSetup(VATPostingSetup);
+
+        // [GIVEN] General journal line with Full VAT Non-Deductible setup
+        LibraryJournals.CreateGenJournalLineWithBatch(
+            GenJournalLine, GenJournalLine."Document Type"::" ", GenJournalLine."Account Type"::"G/L Account",
+            LibraryERM.CreateGLAccountWithVATPostingSetup(VATPostingSetup, GLAccount."Gen. Posting Type"::Purchase),
+            LibraryRandom.RandDec(100, 2));
+
+        // [THEN] "Non-Deductible VAT %" is correctly set to 100 on the journal line (not 0)
+        GenJournalLine.TestField("Non-Deductible VAT %", 100);
+        // [THEN] "Non-Deductible VAT Amount" equals the full amount (Full VAT = entire amount is VAT, 100% non-deductible)
+        GenJournalLine.TestField("Non-Deductible VAT Amount", GenJournalLine.Amount);
+
+        // [WHEN] Post general journal line
+        LibraryERM.PostGeneralJnlLine(GenJournalLine);
