+        Job: Record Job;
+        JobTask: Record "Job Task";
+        JobPlanningLine: Record "Job Planning Line";
+        Location: Record Location;
+        Bin: array[3] of Record Bin;
+        WarehouseEmployee: Record "Warehouse Employee";
+        WarehouseActivityLinePick: Record "Warehouse Activity Line";
+        Quantity: Integer;
+    begin
+        // [SCENARIO] Creating inventory pick for Assembly-to-Order item on job planning line
+        // with Bin Mandatory location should succeed and create ATO pick lines.
+        // Bug: "The Bin does not exist" error in CreatePickOrMoveFromJobPlanning when
+        // location has Bin Mandatory and job planning line has ATO item.
+        Initialize();
+
+        // [GIVEN] Create an assembly item with 2 components and Assembly-to-Order policy.
+        CreateAssemblyItemWithBOM(ParentItem, CompItem1, CompItem2);
+
+        // [GIVEN] Create Location with Bin Mandatory = true, no Require Pick/Shipment.
+        // Job Consump. Whse. Handling = Inventory Pick.
+        LibraryWarehouse.CreateLocationWMS(Location, true, false, false, false, false);
+        Location.Validate("Job Consump. Whse. Handling", Enum::"Job Consump. Whse. Handling"::"Inventory Pick");
+        LibraryWarehouse.CreateBin(Bin[1], Location.Code, LibraryUtility.GenerateRandomCode(Bin[1].FieldNo(Code), Database::Bin), '', '');
+        LibraryWarehouse.CreateBin(Bin[2], Location.Code, LibraryUtility.GenerateRandomCode(Bin[2].FieldNo(Code), Database::Bin), '', '');
