+        // [GIVEN] Modify the requisition line: increase quantity beyond original demand and set Planning Flexibility to None
+        RequisitionLine.SetRange(Type, RequisitionLine.Type::Item);
+        RequisitionLine.SetRange("No.", Item."No.");
+        RequisitionLine.FindFirst();
+        IncreasedQty := SalesOrderQty + LibraryRandom.RandIntInRange(10, 50);
+        RequisitionLine.Validate(Quantity, IncreasedQty);
