+        // [THEN] Surplus reservation entries for the purchase line should not change
+        ReservationEntry.Reset();
+        ReservationEntry.SetRange("Source Type", Database::"Purchase Line");
+        ReservationEntry.SetRange("Source Subtype", PurchaseLine."Document Type");
+        ReservationEntry.SetRange("Source ID", PurchaseLine."Document No.");
+        ReservationEntry.SetRange("Source Ref. No.", PurchaseLine."Line No.");
+        ReservationEntry.SetRange("Reservation Status", ReservationEntry."Reservation Status"::Surplus);
+        SurplusCountAfter := ReservationEntry.Count();
+        ReservationEntry.CalcSums("Quantity (Base)");
+        SurplusQtyAfter := ReservationEntry."Quantity (Base)";
+
+        Assert.AreEqual(SurplusCountBefore, SurplusCountAfter,
