+    [Test]
+    [HandlerFunctions('SetAttributeNameOnlyHandler')]
+    [Scope('OnPrem')]
+    procedure EmptyAttributeValueNotCreatedWhenSettingAttributeNameOnly()
+    var
+        ItemAttribute: Record "Item Attribute";
+        ItemAttributeValue: Record "Item Attribute Value";
+        Item: Record Item;
+        ItemCard: TestPage "Item Card";
+        InitialValueCount: Integer;
+    begin
+        // [SCENARIO] Setting an attribute name without a value on the Item Attribute Value List
+        // should not create an empty Item Attribute Value record.
