+        ProdOrderCompCmtLine.SetRange("Prod. Order BOM Line No.", ProdOrderComponent."Line No.");
+        ProdOrderCompCmtLine.FindFirst();
+        Assert.AreEqual(Comment1, ProdOrderCompCmtLine.Comment, 'Comment on component with Position 1 should match BOM line 1 comment.');
+
+        // [THEN] Component with Position '2' has the comment from BOM line 2.
+        ProdOrderComponent.SetRange(Position, '2');
+        ProdOrderComponent.FindFirst();
+        ProdOrderCompCmtLine.Reset();
+        ProdOrderCompCmtLine.SetRange(Status, ProdOrderComponent.Status);
+        ProdOrderCompCmtLine.SetRange("Prod. Order No.", ProdOrderComponent."Prod. Order No.");
+        ProdOrderCompCmtLine.SetRange("Prod. Order Line No.", ProdOrderComponent."Prod. Order Line No.");
+        ProdOrderCompCmtLine.SetRange("Prod. Order BOM Line No.", ProdOrderComponent."Line No.");
+        ProdOrderCompCmtLine.FindFirst();
+        Assert.AreEqual(Comment2, ProdOrderCompCmtLine.Comment, 'Comment on component with Position 2 should match BOM line 2 comment.');
