+codeunit 134826 "UT Cust. GetPrimaryContact"
+{
+    Subtype = Test;
+    TestPermissions = NonRestrictive;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Customer] [GetPrimaryContact] [UT]
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryUtility: Codeunit "Library - Utility";
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryMarketing: Codeunit "Library - Marketing";
+        LibrarySetupStorage: Codeunit "Library - Setup Storage";
+        isInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure GetPrimaryContactNoPrimaryContactFallsBackToBusinessRelation()
+    var
+        Customer: Record Customer;
+        Contact: Record Contact;
+        ContactBusinessRelation: Record "Contact Business Relation";
+        ResultContact: Record Contact;
+        ContactEmail: Text[80];
+    begin
+        // [SCENARIO] GetPrimaryContact returns contact via Contact Business Relation when customer has no Primary Contact No.
+        // This verifies the fix for: "Field Email on Reminder is empty when customer does not have any contacts"
+        Initialize();
+
+        // [GIVEN] A company contact "C" with E-Mail
+        LibraryMarketing.CreateCompanyContact(Contact);
+        ContactEmail := CopyStr(LibraryUtility.GenerateRandomEmail(), 1, MaxStrLen(Contact."E-Mail"));
+        Contact.Validate("E-Mail", ContactEmail);
+        Contact.Modify(true);
+
+        // [GIVEN] Customer "CUST" with empty Primary Contact No.
+        LibrarySales.CreateCustomer(Customer);
+        Customer.Get(Customer."No.");
+        Customer."Primary Contact No." := '';
+        Customer.Modify();
+
+        // [GIVEN] Remove any auto-created contact business relations for "CUST"
+        ContactBusinessRelation.SetRange("Link to Table", ContactBusinessRelation."Link to Table"::Customer);
+        ContactBusinessRelation.SetRange("No.", Customer."No.");
+        ContactBusinessRelation.DeleteAll();
+
+        // [GIVEN] Contact Business Relation linking "C" to "CUST"
+        Clear(ContactBusinessRelation);
+        LibraryMarketing.CreateBusinessRelationBetweenContactAndCustomer(ContactBusinessRelation, Contact."No.", Customer."No.");
+
+        // [WHEN] GetPrimaryContact is called for "CUST"
+        Customer.GetPrimaryContact(Customer."No.", ResultContact);
+
+        // [THEN] The returned contact is "C" with its email
+        Assert.AreEqual(Contact."No.", ResultContact."No.",
+            'GetPrimaryContact should return the contact linked via Contact Business Relation when Primary Contact No. is empty.');
+        Assert.AreEqual(ContactEmail, ResultContact."E-Mail",
+            'The email of the returned contact should be available for display on the Reminder page.');
+    end;
+
+    local procedure Initialize()
+    var
+        Customer: Record Customer;
+        LibraryApplicationArea: Codeunit "Library - Application Area";
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"UT Cust. GetPrimaryContact");
+        Customer.DeleteAll();
+        LibraryApplicationArea.EnableFoundationSetup();
+        LibrarySetupStorage.Restore();
+
+        if isInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"UT Cust. GetPrimaryContact");
+
+        LibraryERMCountryData.UpdateJournalTemplMandatory(false);
+
+        LibrarySetupStorage.SaveGeneralLedgerSetup();
+        LibrarySetupStorage.Save(Database::"Sales & Receivables Setup");
+        LibrarySetupStorage.Save(Database::"Marketing Setup");
+        isInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"UT Cust. GetPrimaryContact");
+    end;
+}

