+
+namespace Microsoft.Integration.Shopify.Test;
+
+using Microsoft.Integration.Shopify;
+using System.TestLibraries.Utilities;
+using Microsoft.Inventory.Item;
+using Microsoft.Finance.Currency;
+
+/// <summary>
+/// Codeunit Shpfy Create Item Curr. Test (ID 139614).
+/// Tests that item creation from Shopify converts prices using shop currency exchange rates.
+/// </summary>
+codeunit 139614 "Shpfy Create Item Curr. Test"
+{
+    Subtype = Test;
+    TestType = Uncategorized;
+    TestPermissions = Disabled;
+
+    var
+        LibraryAssert: Codeunit "Library Assert";
+        LibraryERM: Codeunit "Library - ERM";
+
+    [Test]
+    procedure UnitTestCreateItemWithCurrencyExchangeConversion()
+    var
+        Item: Record Item;
+        Shop: Record "Shpfy Shop";
+        ShopifyVariant: Record "Shpfy Variant";
+        Currency: Record Currency;
+        CurrencyExchangeRate: Record "Currency Exchange Rate";
+        ProductInitTest: Codeunit "Shpfy Product Init Test";
+        InitializeTest: Codeunit "Shpfy Initialize Test";
+        UnitCost: Decimal;
+        Price: Decimal;
+        ExpectedUnitCost: Decimal;
+        ExpectedUnitPrice: Decimal;
+    begin
+        // [SCENARIO] Create an Item from a Shopify Product when the Shop has a Currency Code set.
+        // The item's Unit Cost and Unit Price should be converted from the shop's foreign currency to LCY.
+
+        // [GIVEN] The Shop with the setting "SKU Mapping" = "Item No." and a Currency Code set with exchange rate.
+        Shop := InitializeTest.CreateShop();
+        Shop."SKU Mapping" := "Shpfy SKU Mapping"::"Item No.";
+
+        LibraryERM.CreateCurrency(Currency);
+        LibraryERM.CreateExchangeRate(Currency.Code, WorkDate(), 100, 50);
+
+        Shop."Currency Code" := Currency.Code;
+        Shop.Modify();
+
+        // [GIVEN] A Shopify variant record with known Unit Cost and Price values in FCY.
+        ShopifyVariant := ProductInitTest.CreateStandardProduct(Shop);
+        UnitCost := 1000;
+        Price := 5000;
+        ShopifyVariant."Unit Cost" := UnitCost;
+        ShopifyVariant.Price := Price;
+        ShopifyVariant.Modify();
+        ShopifyVariant.SetRecFilter();
+
+        // [GIVEN] Expected converted amounts from FCY to LCY.
+        ExpectedUnitCost := Round(CurrencyExchangeRate.ExchangeAmtFCYToLCY(
+            WorkDate(), Currency.Code, UnitCost,
+            CurrencyExchangeRate.ExchangeRate(WorkDate(), Currency.Code)));
+        ExpectedUnitPrice := Round(CurrencyExchangeRate.ExchangeAmtFCYToLCY(
+            WorkDate(), Currency.Code, Price,
+            CurrencyExchangeRate.ExchangeRate(WorkDate(), Currency.Code)));
+
+        // Verify test setup: converted values must differ from raw FCY values
+        LibraryAssert.AreNotEqual(UnitCost, ExpectedUnitCost, 'Test setup: converted unit cost should differ from raw FCY value');
+        LibraryAssert.AreNotEqual(Price, ExpectedUnitPrice, 'Test setup: converted unit price should differ from raw FCY value');
+
+        // [WHEN] Executing the codeunit "Shpfy Create Item" with the "Shpfy Variant" record.
+        Codeunit.Run(Codeunit::"Shpfy Create Item", ShopifyVariant);
+
+        // [THEN] The item must be created.
+        LibraryAssert.IsFalse(IsNullGuid(ShopifyVariant."Item SystemId"), 'Item SystemId <> NullGuid');
+        LibraryAssert.IsTrue(Item.GetBySystemId(ShopifyVariant."Item SystemId"), 'Get Item');
+
+        // [THEN] The Item's Unit Cost should be the converted amount, not the raw Shopify FCY value.
+        LibraryAssert.AreEqual(ExpectedUnitCost, Item."Unit Cost", 'Unit Cost should be converted from FCY to LCY');
+
+        // [THEN] The Item's Unit Price should be the converted amount, not the raw Shopify FCY value.
+        LibraryAssert.AreEqual(ExpectedUnitPrice, Item."Unit Price", 'Unit Price should be converted from FCY to LCY');
+    end;
+}

