+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryUtility: Codeunit "Library - Utility";
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure TotalAmountLCYNotTripledWhenShipAndGetShipmentLines()
+    var
+        Customer: Record Customer;
+        SalesLine: Record "Sales Line";
+        SalesShipmentLine: Record "Sales Shipment Line";
+        OrderDocNo: Code[20];
+        ShipmentDocNo: Code[20];
+        InvoiceDocNo: Code[20];
+        Amount: Decimal;
+    begin
+        // [FEATURE] [Statistics] [Sales]
+        // [SCENARIO] Customer GetTotalAmountLCY should not triple the amount when a Sales Order
+        // is shipped and a Sales Invoice uses Get Shipment Lines to bring in the shipment.
+        // Without fix: Total = ShippedNotInvoiced + OutstandingInvoices + OutstandingFromShipment = 3x Amount
+        // With fix: Total = (ShippedNotInvoiced - ShippedFromOrder) + (OutstandingInvoices - ShippedOutstandingInv) + OutstandingFromShipment = Amount
+
+        // [GIVEN] A new Customer
+        LibrarySales.CreateCustomer(Customer);
+        Amount := 10000;
+        OrderDocNo := LibraryUtility.GenerateGUID();
+        ShipmentDocNo := LibraryUtility.GenerateGUID();
+        InvoiceDocNo := LibraryUtility.GenerateGUID();
+
+        // [GIVEN] Sales Order Line that has been fully shipped but not invoiced
+        // Outstanding Amount = 0 (fully shipped), Shipped Not Invoiced = Amount
+        SalesLine.Init();
+        SalesLine."Document Type" := SalesLine."Document Type"::Order;
+        SalesLine."Document No." := OrderDocNo;
+        SalesLine."Line No." := 10000;
+        SalesLine."Bill-to Customer No." := Customer."No.";
+        SalesLine."Sell-to Customer No." := Customer."No.";
+        SalesLine."Outstanding Amount (LCY)" := 0;
+        SalesLine."Shipped Not Invoiced (LCY)" := Amount;
+        SalesLine.Insert();
+
+        // [GIVEN] Sales Shipment Line referencing the order
+        SalesShipmentLine.Init();
+        SalesShipmentLine."Document No." := ShipmentDocNo;
+        SalesShipmentLine."Line No." := 10000;
+        SalesShipmentLine."Bill-to Customer No." := Customer."No.";
+        SalesShipmentLine."Sell-to Customer No." := Customer."No.";
+        SalesShipmentLine."Order No." := OrderDocNo;
+        SalesShipmentLine."Order Line No." := 10000;
+        SalesShipmentLine.Insert();
+
+        // [GIVEN] Sales Invoice Line created via Get Shipment Lines (references the shipment)
+        SalesLine.Init();
+        SalesLine."Document Type" := SalesLine."Document Type"::Invoice;
+        SalesLine."Document No." := InvoiceDocNo;
+        SalesLine."Line No." := 10000;
+        SalesLine."Bill-to Customer No." := Customer."No.";
+        SalesLine."Sell-to Customer No." := Customer."No.";
+        SalesLine."Outstanding Amount (LCY)" := Amount;
+        SalesLine."Shipment No." := ShipmentDocNo;
+        SalesLine."Shipment Line No." := 10000;
+        SalesLine.Insert();
+
+        // [WHEN] Calculate Customer's Total Amount LCY
+        // [THEN] Total Amount equals Amount, not tripled
+        Assert.AreEqual(Amount, Customer.GetTotalAmountLCY(), 'Total Amount LCY should not be tripled when invoice is created from shipment lines');
+    end;
+}

