+codeunit 137113 "SCM BOM CostShares Consistency"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        isInitialized := false;
+    end;
+
+    var
+        LibraryAssembly: Codeunit "Library - Assembly";
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+        LibraryManufacturing: Codeunit "Library - Manufacturing";
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        Assert: Codeunit Assert;
+        isInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure RolledUpCapCostSameForMfgItemWithNoBOMAndEmptyBOM()
+    var
+        ParentItem: Record Item;
+        ChildItem: Record Item;
+        ParentProdBOMHeader: Record "Production BOM Header";
+        EmptyProdBOMHeader: Record "Production BOM Header";
+        BOMBuffer: Record "BOM Buffer";
+        RolledUpCapCostEmptyBOM: Decimal;
+        RolledUpCapCostNoBOM: Decimal;
+        QtyPer: Decimal;
+    begin
+        // [FEATURE] [BOM Tree] [SCM]
+        // [SCENARIO] Rolled-up Capacity Cost for a manufacturing component in BOM Cost Shares
+        // should be the same whether the component has an empty Production BOM or no Production BOM.
+        // A blank Production BOM is equivalent to no Production BOM for cost calculation purposes.
+
+        // [GIVEN] Setup
+        Initialize();
+        QtyPer := LibraryRandom.RandIntInRange(3, 8);
+
+        // [GIVEN] A child manufacturing item with a routing (generating capacity costs) but no Production BOM
+        CreateMfgItemWithRoutingCosts(ChildItem);
+
+        // [GIVEN] A parent manufacturing item whose Production BOM includes the child component
+        CreateParentItemWithChildComponent(ParentItem, ParentProdBOMHeader, ChildItem, QtyPer);
+
+        // [GIVEN] An empty certified Production BOM is assigned to the child item
+        CreateEmptyProductionBOM(EmptyProdBOMHeader, ChildItem."Base Unit of Measure");
+        ChildItem.Validate("Production BOM No.", EmptyProdBOMHeader."No.");
+        ChildItem.Modify(true);
+
+        // [WHEN] BOM tree cost is calculated with the child having an empty Production BOM
+        CalculateCostTree(BOMBuffer, ParentItem);
+
+        // [THEN] Record the Rolled-up Capacity Cost for the child with the empty BOM
+        FindBOMBufferEntry(BOMBuffer, BOMBuffer.Type::Item, ChildItem."No.");
+        RolledUpCapCostEmptyBOM := BOMBuffer."Rolled-up Capacity Cost";
+        Assert.AreNotEqual(0, RolledUpCapCostEmptyBOM, 'Rolled-up Capacity Cost must not be zero with empty BOM.');
+
+        // [GIVEN] The Production BOM is removed from the child item (field set to blank)
+        ChildItem.Get(ChildItem."No.");
+        ChildItem.Validate("Production BOM No.", '');
+        ChildItem.Modify(true);
+
+        // [WHEN] BOM tree cost is recalculated with the child having no Production BOM
+        Clear(BOMBuffer);
+        CalculateCostTree(BOMBuffer, ParentItem);
+
+        // [THEN] Rolled-up Capacity Cost for the child should be the same as with the empty BOM
+        FindBOMBufferEntry(BOMBuffer, BOMBuffer.Type::Item, ChildItem."No.");
+        RolledUpCapCostNoBOM := BOMBuffer."Rolled-up Capacity Cost";
+
+        Assert.AreEqual(
+            RolledUpCapCostEmptyBOM,
+            RolledUpCapCostNoBOM,
+            'Rolled-up Capacity Cost must be the same whether the component has an empty Production BOM or no Production BOM.');
+    end;
+
+    local procedure Initialize()
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"SCM BOM CostShares Consistency");
+        if isInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"SCM BOM CostShares Consistency");
+
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+
+        isInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"SCM BOM CostShares Consistency");
+    end;
+
+    local procedure CreateMfgItemWithRoutingCosts(var Item: Record Item)
+    var
+        RoutingLine: Record "Routing Line";
+        WorkCenter: Record "Work Center";
+        MachineCenter: Record "Machine Center";
+    begin
+        LibraryAssembly.CreateItem(Item, Item."Costing Method"::Standard, Item."Replenishment System"::"Prod. Order", '', '');
+        Item.Validate("Lot Size", 1);
+        Item.Modify(true);
+
+        LibraryAssembly.CreateRouting(Item, 2);
+
+        RoutingLine.SetRange("Routing No.", Item."Routing No.");
+        if RoutingLine.FindSet() then
+            repeat
+                case RoutingLine.Type of
+                    RoutingLine.Type::"Work Center":
+                        begin
+                            WorkCenter.Get(RoutingLine."No.");
+                            WorkCenter.Validate("Direct Unit Cost", LibraryRandom.RandDecInRange(5, 20, 2));
+                            WorkCenter.Modify(true);
+                        end;
+                    RoutingLine.Type::"Machine Center":
+                        begin
+                            MachineCenter.Get(RoutingLine."No.");
+                            MachineCenter.Validate("Direct Unit Cost", LibraryRandom.RandDecInRange(5, 20, 2));
+                            MachineCenter.Modify(true);
+                        end;
+                end;
+            until RoutingLine.Next() = 0;
+    end;
+
+    local procedure CreateParentItemWithChildComponent(var ParentItem: Record Item; var ProdBOMHeader: Record "Production BOM Header"; ChildItem: Record Item; QtyPer: Decimal)
+    var
+        ProductionBOMLine: Record "Production BOM Line";
+    begin
+        LibraryAssembly.CreateItem(ParentItem, ParentItem."Costing Method"::Standard, ParentItem."Replenishment System"::"Prod. Order", '', '');
+        ParentItem.Validate("Lot Size", 1);
+        ParentItem.Modify(true);
+
+        LibraryManufacturing.CreateProductionBOMHeader(ProdBOMHeader, ParentItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProdBOMHeader, ProductionBOMLine, '', ProductionBOMLine.Type::Item, ChildItem."No.", QtyPer);
+        LibraryManufacturing.UpdateProductionBOMStatus(ProdBOMHeader, ProdBOMHeader.Status::Certified);
+
+        ParentItem.Validate("Production BOM No.", ProdBOMHeader."No.");
+        ParentItem.Modify(true);
+    end;
+
+    local procedure CreateEmptyProductionBOM(var ProdBOMHeader: Record "Production BOM Header"; UnitOfMeasureCode: Code[10])
