+codeunit 137085 "SCM Prod. Order Stats Test"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Manufacturing] [Production Order] [SCM]
+        IsInitialized := false;
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryManufacturing: Codeunit "Library - Manufacturing";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibrarySetupStorage: Codeunit "Library - Setup Storage";
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+        IsInitialized: Boolean;
+
+    [Test]
+    procedure MfgOverheadExpCostCorrectForMultiLineProdOrder()
+    var
+        RawItem: Record Item;
+        FGItem: Record Item;
+        ProductionBOMHeader: Record "Production BOM Header";
+        ProductionBOMLine: Record "Production BOM Line";
+        ProductionOrder: Record "Production Order";
+        ProdOrderLine: Record "Prod. Order Line";
+        ProductionOrderStatistics: TestPage "Production Order Statistics";
+        RawUnitCost: Decimal;
+        IndirectCostPct: Decimal;
+        QtyPerLine: Decimal;
+        TotalMaterialCost: Decimal;
+        ExpectedMfgOvhdCost: Decimal;
+    begin
+        // [SCENARIO] Manufacturing overhead expected cost must be correct on Production Order Statistics
+        // when a production order has multiple lines for the same finished good item with Indirect Cost %.
+        // With the old code, the overhead was double-counted because the indirect cost percentage was
+        // applied to the accumulated total direct cost and then added to the already accumulated overhead.
+        // For two lines of 10 FG (material cost 1000 each), the old code gave 300 instead of 200.
+        Initialize();
+
+        // [GIVEN] A raw material item with Unit Cost = 100.
+        RawUnitCost := 100;
+        LibraryInventory.CreateItem(RawItem);
+        RawItem.Validate("Unit Cost", RawUnitCost);
+        RawItem.Modify(true);
+
+        // [GIVEN] A finished good item with Indirect Cost % = 10.
+        IndirectCostPct := 10;
+        LibraryInventory.CreateItem(FGItem);
+        FGItem.Validate("Replenishment System", FGItem."Replenishment System"::"Prod. Order");
+        FGItem.Validate("Indirect Cost %", IndirectCostPct);
+
+        // [GIVEN] A certified Production BOM with the raw material item, Quantity per = 1, assigned to the FG item.
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, FGItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeader, ProductionBOMLine, '', ProductionBOMLine.Type::Item, RawItem."No.", 1);
+        ProductionBOMHeader.Validate(Status, ProductionBOMHeader.Status::Certified);
+        ProductionBOMHeader.Modify(true);
+        FGItem.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        FGItem.Modify(true);
+
+        // [GIVEN] A released production order with two lines for FG item, each with Quantity = 10.
+        QtyPerLine := 10;
+        LibraryManufacturing.CreateProductionOrder(
+            ProductionOrder, ProductionOrder.Status::Released,
+            ProductionOrder."Source Type"::Item, FGItem."No.", QtyPerLine * 2);
+        LibraryManufacturing.CreateProdOrderLine(
+            ProdOrderLine, ProductionOrder.Status, ProductionOrder."No.", FGItem."No.", '', '', QtyPerLine);
+        LibraryManufacturing.CreateProdOrderLine(
+            ProdOrderLine, ProductionOrder.Status, ProductionOrder."No.", FGItem."No.", '', '', QtyPerLine);
+
+        // [GIVEN] Refresh Production Order without recalculating lines to keep the two manual lines.
+        LibraryManufacturing.RefreshProdOrder(ProductionOrder, false, false, true, true, false);
+
+        // [WHEN] Open Production Order Statistics page for the production order.
+        ProductionOrderStatistics.OpenView();
+        ProductionOrderStatistics.GoToRecord(ProductionOrder);
+
+        // [THEN] Manufacturing Overhead Expected Cost equals Indirect Cost % of total material cost.
+        // Total material = 20 units * 100 unit cost = 2000. Mfg Overhead = 10% of 2000 = 200.
+        TotalMaterialCost := QtyPerLine * 2 * RawUnitCost;
+        ExpectedMfgOvhdCost := Round(TotalMaterialCost * IndirectCostPct / 100);
+        Assert.AreEqual(
+            ExpectedMfgOvhdCost,
+            ProductionOrderStatistics.MfgOverhead_ExpectedCost.AsDecimal(),
+            'Manufacturing Overhead Expected Cost must equal Indirect Cost % applied to total material cost.');
+        ProductionOrderStatistics.Close();
+    end;
+
+    local procedure Initialize()
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"SCM Prod. Order Stats Test");
+        LibrarySetupStorage.Restore();
+
+        if IsInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"SCM Prod. Order Stats Test");
+
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        LibrarySetupStorage.SaveManufacturingSetup();
+
+        IsInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"SCM Prod. Order Stats Test");
+    end;
+}

