+namespace Microsoft.Finance.ExcelReports.Test;
+
+using Microsoft.Finance.ExcelReports;
+
+codeunit 139546 "Trial Balance Buffer Tests"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    var
+        Assert: Codeunit Assert;
+
+    [Test]
+    procedure NetChangeDebitClearedWhenSignChangesToNegative()
+    var
+        TrialBalanceBuffer: Record "EXR Trial Balance Buffer" temporary;
+    begin
+        // [SCENARIO] When a buffer record's "Net Change" switches from positive to negative,
+        // the "Net Change (Debit)" field must be reset to 0 so stale values are not carried over.
+        // This reproduces the repeated-values bug in the Trial Balance Excel report when
+        // dimension breakdown causes the buffer to be reused with different sign amounts.
+
+        // [GIVEN] A Trial Balance Buffer record with a positive Net Change
+        TrialBalanceBuffer.Init();
+        TrialBalanceBuffer."G/L Account No." := 'TEST';
+        TrialBalanceBuffer.Validate("Net Change", 100);
+
+        // Verify initial state: Debit populated, Credit zero
+        Assert.AreEqual(100, TrialBalanceBuffer."Net Change (Debit)", 'Net Change (Debit) should be 100 for positive net change');
+        Assert.AreEqual(0, TrialBalanceBuffer."Net Change (Credit)", 'Net Change (Credit) should be 0 for positive net change');
+
+        // [WHEN] The same record is revalidated with a negative Net Change (simulating dimension breakdown reuse)
+        TrialBalanceBuffer.Validate("Net Change", -50);
+
+        // [THEN] Net Change (Credit) should be the absolute value, and Net Change (Debit) must be zeroed out
+        Assert.AreEqual(50, TrialBalanceBuffer."Net Change (Credit)", 'Net Change (Credit) should be 50 for negative net change');
+        Assert.AreEqual(0, TrialBalanceBuffer."Net Change (Debit)", 'Net Change (Debit) must be reset to 0 when net change becomes negative');
+
+        // [THEN] Also verify the reverse: going from negative back to positive clears credit
+        TrialBalanceBuffer.Validate("Net Change", 75);
+        Assert.AreEqual(75, TrialBalanceBuffer."Net Change (Debit)", 'Net Change (Debit) should be 75 for positive net change');
+        Assert.AreEqual(0, TrialBalanceBuffer."Net Change (Credit)", 'Net Change (Credit) must be reset to 0 when net change becomes positive');
+
