+        Assert: Codeunit Assert;
+        isInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure CalcRegenPlanWithSKUProductionBOMPlansComponent()
+    var
+        ComponentItem: Record Item;
+        ParentItem: Record Item;
+        ProductionBOMHeader: Record "Production BOM Header";
+        ProductionBOMLine: Record "Production BOM Line";
+        SKUParent: Record "Stockkeeping Unit";
+        SKUComponent: Record "Stockkeeping Unit";
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        RequisitionLine: Record "Requisition Line";
+        MfgSetup: Record "Manufacturing Setup";
+        Location: Record Location;
+        ItemFilter: Record Item;
+        DemandQty: Decimal;
+    begin
+        // [SCENARIO 537083] Calculate Regenerative Plan with SKUs having Production BOM plans both parent and component in single run.
+        // [GIVEN] Manufacturing Setup with Dynamic Low-Level Code enabled.
+        // [GIVEN] Component item with SKU at a location, Replenishment System = Purchase, Reorder Policy = Order.
+        // [GIVEN] Parent item with SKU at the same location, Replenishment System = Prod. Order, Production BOM set on SKU (not on Item).
+        // [GIVEN] Sales Order for parent item at the location.
+        // [WHEN] Calculate Regenerative Plan is run once for both items.
+        // [THEN] Requisition lines are created for both parent and component items.
+        Initialize();
+
+        // Setup: Ensure Dynamic Low-Level Code is enabled in Manufacturing Setup.
+        MfgSetup.Get();
+        if not MfgSetup."Dynamic Low-Level Code" then begin
+            MfgSetup."Dynamic Low-Level Code" := true;
+            MfgSetup.Modify(true);
+        end;
+
+        // Setup: Create Location.
+        LibraryWarehouse.CreateLocation(Location);
+
+        // Setup: Create Component Item and Parent Item.
+        LibraryInventory.CreateItem(ComponentItem);
+        LibraryInventory.CreateItem(ParentItem);
+
+        // Setup: Create certified Production BOM with Component using Parent's base unit of measure.
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, ParentItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeader, ProductionBOMLine, '', ProductionBOMLine.Type::Item, ComponentItem."No.", 1);
+        ProductionBOMHeader.Validate(Status, ProductionBOMHeader.Status::Certified);
+        ProductionBOMHeader.Modify(true);
+
+        // Setup: Create SKU for Component at Location with Purchase replenishment and Order reorder policy.
+        CreateStockkeepingUnit(ComponentItem, Location.Code, SKUComponent);
+        SKUComponent.Validate("Replenishment System", SKUComponent."Replenishment System"::Purchase);
+        SKUComponent.Validate("Reordering Policy", SKUComponent."Reordering Policy"::Order);
+        SKUComponent.Modify(true);
+
+        // Setup: Create SKU for Parent at Location with Prod. Order replenishment, Lot-for-Lot reorder, and Production BOM on SKU.
+        CreateStockkeepingUnit(ParentItem, Location.Code, SKUParent);
+        SKUParent.Validate("Replenishment System", SKUParent."Replenishment System"::"Prod. Order");
+        SKUParent.Validate("Reordering Policy", SKUParent."Reordering Policy"::"Lot-for-Lot");
+        SKUParent.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        SKUParent.Modify(true);
+
+        // Setup: Create Sales Order for Parent Item at Location.
+        DemandQty := LibraryRandom.RandIntInRange(5, 20);
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Order, '');
+        SalesHeader.Validate("Location Code", Location.Code);
+        SalesHeader.Modify(true);
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, ParentItem."No.", DemandQty);
+        SalesLine.Validate("Location Code", Location.Code);
+        SalesLine.Validate("Shipment Date", CalcDate('<+1M>', WorkDate()));
+        SalesLine.Modify(true);
+
+        // Exercise: Calculate Regenerative Plan for both items in a single run.
+        ItemFilter.SetFilter("No.", '%1|%2', ParentItem."No.", ComponentItem."No.");
+        LibraryPlanning.CalcRegenPlanForPlanWksh(ItemFilter, WorkDate(), CalcDate('<+2M>', WorkDate()));
+
+        // Verify: Requisition line exists for Parent Item.
+        RequisitionLine.SetRange(Type, RequisitionLine.Type::Item);
+        RequisitionLine.SetRange("No.", ParentItem."No.");
+        Assert.RecordIsNotEmpty(RequisitionLine);
+
+        // Verify: Requisition line exists for Component Item (this failed without the fix).
+        RequisitionLine.SetRange("No.", ComponentItem."No.");
+        Assert.RecordIsNotEmpty(RequisitionLine);
+    end;
+
+    local procedure Initialize()
+    var
+        RequisitionLine: Record "Requisition Line";
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"SCM Plan. SKU Low-Level Code");
+        RequisitionLine.DeleteAll();
+
+        if isInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"SCM Plan. SKU Low-Level Code");
+
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdatePurchasesPayablesSetup();
+        LibraryERMCountryData.UpdateSalesReceivablesSetup();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+
+        isInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"SCM Plan. SKU Low-Level Code");
+    end;
+
+    local procedure CreateStockkeepingUnit(var Item: Record Item; LocationCode: Code[10]; var SKU: Record "Stockkeeping Unit")
+    begin
+        Item.SetRange("Location Filter", LocationCode);
+        LibraryInventory.CreateStockKeepingUnit(Item, "SKU Creation Method"::Location, false, false);
+        SKU.Get(LocationCode, Item."No.", '');
+    end;
+}

