+        CreateReqWkshBatch(ReqWkshNameTarget, ReqWkshTemplate.Name, 'ZBATCH');
+
+        // [GIVEN] A requisition line exists only in ZBATCH (not the alphabetically first batch)
+        CreateRequisitionLine(RequisitionLine, ReqWkshTemplate.Name, ReqWkshNameTarget.Name);
