+        Assert: Codeunit Assert;
+        isInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure CarryOutActionMsgRespectsActionMessageFilter()
+    var
+        ItemCancel: Record Item;
+        ItemNew: Record Item;
+        Vendor: Record Vendor;
+        PurchaseHeader: Record "Purchase Header";
+        PurchaseLine: Record "Purchase Line";
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        RequisitionLine: Record "Requisition Line";
+        Item: Record Item;
+        Quantity: Decimal;
+    begin
+        // [FEATURE] [Planning Worksheet] [Carry Out Action Message]
+        // [SCENARIO] When Carry Out Action Message is run with an Action Message filter applied,
+        // only the lines matching the filter should be carried out, not all lines in the worksheet.
+        Initialize();
+
+        // [GIVEN] Two items with Reordering Policy = Order and Replenishment System = Purchase.
+        LibraryPurchase.CreateVendor(Vendor);
+        CreatePurchaseItem(ItemCancel, Vendor."No.");
+        CreatePurchaseItem(ItemNew, Vendor."No.");
+        Quantity := LibraryRandom.RandIntInRange(1, 10);
+
+        // [GIVEN] A purchase order exists for ItemCancel (supply with no demand -> will produce Cancel action).
+        LibraryPurchase.CreatePurchaseDocumentWithItem(
+            PurchaseHeader, PurchaseLine, PurchaseHeader."Document Type"::Order,
+            Vendor."No.", ItemCancel."No.", Quantity, '', WorkDate());
+
+        // [GIVEN] A sales order exists for ItemNew (demand with no supply -> will produce New action).
+        LibrarySales.CreateSalesDocumentWithItem(
+            SalesHeader, SalesLine, SalesHeader."Document Type"::Order,
+            '', ItemNew."No.", Quantity, '', CalcDate('<+1M>', WorkDate()));
+
+        // [GIVEN] Calculate regenerative plan for both items.
+        Item.SetFilter("No.", '%1|%2', ItemCancel."No.", ItemNew."No.");
+        LibraryPlanning.CalcRegenPlanForPlanWksh(Item, WorkDate(), CalcDate('<+2M>', WorkDate()));
+
+        // [GIVEN] Verify prerequisite: Cancel action message exists for ItemCancel.
+        VerifyRequisitionLineExists(ItemCancel."No.", RequisitionLine."Action Message"::Cancel);
+
+        // [GIVEN] Verify prerequisite: New action message exists for ItemNew.
+        VerifyRequisitionLineExists(ItemNew."No.", RequisitionLine."Action Message"::New);
+
+        // [GIVEN] Accept action message on all planning lines.
+        AcceptActionMessages(ItemCancel."No.");
