+codeunit 137003 "SCM Res. Entry Qty. Rounding"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Reservation] [Order Tracking] [SCM]
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibrarySales: Codeunit "Library - Sales";
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure SumOfSplitTrackingEntriesWithNonBaseUOMIsCorrect()
+    var
+        ReservationEntry: array[3] of Record "Reservation Entry";
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        Item: Record Item;
+        TotalQuantity: Decimal;
+        QtyPerUOM: Decimal;
+    begin
+        // [SCENARIO 530077] CalcReservationQuantity includes Tracking status entries to prevent
+        // rounding error when tracking lines are split into 3 entries each ending in x.xxxx7.
+        // Without the fix, 0.54167 + 9.16667 + 2.29167 = 12.00001 instead of 12.
+
+        // [GIVEN] Item with a sales order (source document for reservation entries)
+        QtyPerUOM := 24;
+        LibraryInventory.CreateItem(Item);
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Order, LibrarySales.CreateCustomerNo());
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, Item."No.", 1);
+
+        // [GIVEN] Two existing Tracking reservation entries for the sales line with Qty. per UOM = 24
+        // 13/24 = 0.54167 and 220/24 = 9.16667 (individually rounded to 5 decimals)
+        InsertTrackingReservEntry(ReservationEntry[1], Item."No.", SalesLine, QtyPerUOM, -13, -0.54167);
+        InsertTrackingReservEntry(ReservationEntry[2], Item."No.", SalesLine, QtyPerUOM, -220, -9.16667);
+
+        // [WHEN] A third Tracking entry with base quantity 55 has its Quantity (Base) validated
+        // This triggers CalcReservationQuantity which must find the other Tracking entries
+        InsertAndValidateTrackingReservEntry(ReservationEntry[3], Item."No.", SalesLine, QtyPerUOM, -55);
+
+        // [THEN] The sum of Quantity across all 3 entries is exactly -12, not -12.00001
+        ReservationEntry[1].Get(ReservationEntry[1]."Entry No.", false);
+        ReservationEntry[2].Get(ReservationEntry[2]."Entry No.", false);
+        TotalQuantity :=
+            ReservationEntry[1].Quantity +
+            ReservationEntry[2].Quantity +
+            ReservationEntry[3].Quantity;
+        Assert.AreEqual(-12, TotalQuantity,
+            'Total Quantity of split tracking entries must not have rounding error.');
+    end;
+
+    local procedure InsertTrackingReservEntry(var ReservEntry: Record "Reservation Entry"; ItemNo: Code[20]; SalesLine: Record "Sales Line"; QtyPerUOM: Decimal; QtyBase: Decimal; Qty: Decimal)
+    begin
+        InitTrackingReservEntry(ReservEntry, ItemNo, SalesLine, QtyPerUOM);
+        ReservEntry."Quantity (Base)" := QtyBase;
+        ReservEntry.Quantity := Qty;
+        ReservEntry."Qty. to Handle (Base)" := QtyBase;
+        ReservEntry."Qty. to Invoice (Base)" := QtyBase;
+        ReservEntry.Insert(false);
+    end;
+
+    local procedure InsertAndValidateTrackingReservEntry(var ReservEntry: Record "Reservation Entry"; ItemNo: Code[20]; SalesLine: Record "Sales Line"; QtyPerUOM: Decimal; QtyBase: Decimal)
+    begin
+        InitTrackingReservEntry(ReservEntry, ItemNo, SalesLine, QtyPerUOM);
+        ReservEntry.Insert(false);
+        // Validate Quantity (Base) to trigger CalcReservationQuantity
+        ReservEntry.Validate("Quantity (Base)", QtyBase);
+        ReservEntry.Modify(false);
+    end;
+
+    local procedure InitTrackingReservEntry(var ReservEntry: Record "Reservation Entry"; ItemNo: Code[20]; SalesLine: Record "Sales Line"; QtyPerUOM: Decimal)
+    var
+        LastEntryNo: Integer;
+    begin
+        ReservEntry.Reset();
+        if ReservEntry.FindLast() then
+            LastEntryNo := ReservEntry."Entry No."
+        else
+            LastEntryNo := 0;
+
+        ReservEntry.Init();
+        ReservEntry."Entry No." := LastEntryNo + 1;
+        ReservEntry.Positive := false;
+        ReservEntry."Reservation Status" := ReservEntry."Reservation Status"::Tracking;
+        ReservEntry."Item No." := ItemNo;
+        ReservEntry."Source Type" := DATABASE::"Sales Line";
+        ReservEntry."Source Subtype" := SalesLine."Document Type".AsInteger();
+        ReservEntry."Source ID" := SalesLine."Document No.";
+        ReservEntry."Source Ref. No." := SalesLine."Line No.";
+        ReservEntry."Qty. per Unit of Measure" := QtyPerUOM;
+        ReservEntry."Shipment Date" := WorkDate();
+        ReservEntry."Creation Date" := WorkDate();
+    end;
+}

